function coletaDadosCard(){document.querySelector("#botao-salvar-roupa").addEventListener("click",function(){var e=document.querySelector(".carrosel-roupas img").src;let t=document.querySelector(".alerta-de-salvamento-de-roupa");localStorage.setItem("roupaEscolhida",e),t.style.display="flex",setTimeout(function(){t.style.transform="translateY(0)",setTimeout(function(){t.style.transform="translateY(300%)",setTimeout(function(){t.style.display="none"},300)},800)},500)})}export{coletaDadosCard};